// Parse HARO email digest and extract journalist queries
// HARO sends 3 digest emails/day with multiple queries

const items = [];
const keywords = [
  'food', 'meal', 'recipe', 'cook', 'kitchen', 'pantry', 'nutrition', 'restaurant', 'diet',
  'ai', 'artificial intelligence', 'machine learning', 'automation', 'saas', 'software',
  'dental', 'dentist',
  'booking', 'appointment', 'scheduling',
  'real estate', 'wholesale', 'property',
  'small business', 'entrepreneur', 'founder', 'startup', 'bootstrap',
  'solopreneur', 'remote work', 'technology', 'app', 'mobile'
];

for (const item of .all()) {
  const subject = item.json.subject || '';
  const textBody = item.json.text || item.json.textPlain || item.json.html || '';
  const from = item.json.from || '';

  // Only process emails from HARO/Connectively
  const isHARO = from.toLowerCase().includes('haro') || 
                  from.toLowerCase().includes('connectively') || 
                  from.toLowerCase().includes('helpareporter') ||
                  subject.toLowerCase().includes('haro') ||
                  subject.toLowerCase().includes('help a reporter');

  if (!isHARO) continue;

  // Extract individual queries - HARO formats them as sections
  // Each query has a topic, description, deadline, and reporter name
  const queryBlocks = textBody.split(/\n[-=]{3,}\n|\n\*{3,}\n/);

  for (const block of queryBlocks) {
    if (block.length < 50) continue;

    const searchText = block.toLowerCase();
    const matchedKeywords = keywords.filter(kw => searchText.includes(kw.toLowerCase()));

    if (matchedKeywords.length > 0) {
      // Extract deadline if present
      const deadlineMatch = block.match(/deadline[:\s]+([^\n]+)/i);
      const deadline = deadlineMatch ? deadlineMatch[1].trim() : '';

      // Get first meaningful line as title
      const lines = block.trim().split('\n').filter(l => l.trim().length > 10);
      const title = lines[0] ? lines[0].trim().substring(0, 150) : 'HARO Query';
      const description = lines.slice(0, 8).join('\n').substring(0, 1500);

      items.push({
        json: {
          title,
          description,
          deadline,
          emailSubject: subject,
          matchedKeywords,
          source: 'email'
        }
      });
    }
  }

  // Fallback: if no blocks found but email matches, treat whole email as one query
  if (items.length === 0 && isHARO) {
    const searchText = (subject + ' ' + textBody).toLowerCase();
    const matchedKeywords = keywords.filter(kw => searchText.includes(kw.toLowerCase()));
    if (matchedKeywords.length > 0) {
      items.push({
        json: {
          title: subject,
          description: textBody.substring(0, 2000),
          deadline: '',
          emailSubject: subject,
          matchedKeywords,
          source: 'email-full'
        }
      });
    }
  }
}

console.log('Extracted ' + items.length + ' relevant queries from emails');
return items.length > 0 ? items : [{ json: { noMatch: true, reason: 'no_haro_email_matches' } }];

